import math
fx=fy=0
for i in range(int(input())): 
    F,dir=input().split()
    F = int(F)
    if dir == 'UP': 
        fy += F
    elif dir == 'DOWN': 
        fy -= F
    elif dir == 'RIGHT': 
        fx += F
    else: 
        fx -= F

fx *= -1
fy *= -1

result = f'{math.sqrt(fx**2+fy**2):.2f}'
theta = math.atan2(abs(fy),abs(fx))*180/math.pi



if fx > 0: 
    if fy == 0: 
        theta = 0
    elif fy > 0: 
        theta = theta
    elif fy < 0: 
        theta = 360 - theta
elif fx < 0: 
    if fy == 0: 
        theta = 180
    elif fy > 0: 
        theta = 180 - theta
    elif fy < 0: 
        theta = 180 + theta
else: 
    if fy == 0:
        theta = 0 
    elif fy > 0: 
        theta = 90 
    else: 
        theta = 270

print(result)
print(f'{theta:.2f}')
